async (params, browser) => {
  // Open page
  await browser.open(`https://www.goodreads.com/shelf/show/${params.genre}`)

  // Wait for content
  await browser.waitForSelector('div.leftContainer, [class*=\'BookList\']', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const books = Array.from(document.querySelectorAll('div.elementList, [class*="BookCard"], .leftContainer .bookBox')).slice(0,30).map((el,i) => { const t = el.querySelector('a.bookTitle, a[href*="/book/show/"]'); const a = el.querySelector('a.authorName, a[href*="/author/"]'); const r = el.querySelector('[class*="minirating"], .greyText.smallText'); return { rank: i+1, title: t?t.textContent.trim():'', url: t?t.href:'', author: a?a.textContent.trim():'', rating: r?r.textContent.trim():'' }; }).filter(b=>b.title); return { genre: '' + params.genre + '', book_count: books.length, books, url: window.location.href }`)

  return page_data
}
